import base64, gzip, json
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
DATA = ROOT / "android-learning" / "data"
LESSON_PATH = DATA / "lessons" / "c" / "c08.json"
PAYLOAD = """"""
LESSON_PATH.parent.mkdir(parents=True, exist_ok=True)
LESSON_PATH.write_bytes(gzip.decompress(base64.b64decode(PAYLOAD)))
lesson = json.loads(LESSON_PATH.read_text())

sections = lesson["sections"]
section_ids = [s["id"] for s in sections]
paragraphs = [b["content"] for s in sections for b in s.get("blocks", []) if b.get("type") == "paragraph"]
code_blocks = [b for s in sections for b in s.get("blocks", []) if b.get("type") == "code"]
quiz = lesson["quiz"]
assert len(sections) == 24 and len(section_ids) == len(set(section_ids))
assert len(paragraphs) >= 40 and sum(map(len, paragraphs)) >= 12000
assert len(code_blocks) >= 8 and len(quiz) >= 10
for q in quiz:
    ids = {str(o["id"]) for o in q["options"]}
    assert q["correctOptionIds"] and set(map(str, q["correctOptionIds"])).issubset(ids)
    assert q["explanation"].strip()
text = LESSON_PATH.read_text()
for marker in ("confirmed", "inferred", "proposed", "needs-confirmation"):
    assert marker in text

catalog_path = DATA / "catalog.json"
catalog = json.loads(catalog_path.read_text())
chapter = next(ch for ch in catalog["chapters"] if ch["id"] == "c")
entry = next(item for item in chapter["lessons"] if item["id"] == "c08")
assert entry["status"] in ("planned", "published")
entry["status"] = "published"
entry["estimatedMinutes"] = lesson["estimatedMinutes"]
catalog_path.write_text(json.dumps(catalog, ensure_ascii=False, indent=2) + "\n")

plan_path = DATA / "book-plan.json"
plan = json.loads(plan_path.read_text())
assert plan["current"] in ("c08", "c09")
if "c08" not in plan["completed"]: plan["completed"].append("c08")
plan["current"] = "c09"
plan_path.write_text(json.dumps(plan, ensure_ascii=False, indent=2) + "\n")

index_path = DATA / "search-index.json"
index = json.loads(index_path.read_text())
if not any(x["lessonId"] == "c08" for x in index):
    index.append({"lessonId":"c08","code":"C08","title":"Debounce và Search Flow","keywords":["debounce","search flow","flatMapLatest","distinctUntilChanged","stale result","generation guard","Paging 3","SearchKey","canonical query","virtual time"],"headings":["Debounce mechanism","Operator order","Latest-only cancellation","Loading and empty state","Paging search","Cache and single-flight","Upzi case study","Virtual-time testing"]})
index_path.write_text(json.dumps(index, ensure_ascii=False, indent=2) + "\n")

report = {"id":"c08","sections":len(sections),"uniqueSectionIds":len(set(section_ids)),"paragraphs":len(paragraphs),"paragraphCharacters":sum(map(len,paragraphs)),"codeBlocks":len(code_blocks),"quizQuestions":len(quiz),"quizAnswersValid":True,"truthfulnessLabelsPresent":True}
(ROOT / "validation-c08.json").write_text(json.dumps(report, ensure_ascii=False, indent=2) + "\n")
print(json.dumps(report, ensure_ascii=False, indent=2))
